import React, { useEffect, useState } from 'react';
import { Search, Eye, Edit2, CheckCircle, XCircle, AlertCircle, ToggleLeft } from 'lucide-react';
import Card from '../../components/ui/Card';
import Badge from '../../components/ui/Badge';
import Button from '../../components/ui/Button';
import Input from '../../components/ui/Input';
import Select from '../../components/ui/Select';
import Modal from '../../components/ui/Modal';
import { supabase } from '../../lib/supabase';

interface Seller {
  id: string;
  store_name: string;
  owner_id: string;
  owner_email?: string;
  category: string;
  status: 'active' | 'pending' | 'suspended' | 'rejected';
  products_count: number;
  total_earnings: number;
  is_verified: boolean;
  commission_rate: number;
}

const Sellers = () => {
  const [sellers, setSellers] = useState<Seller[]>([]);
  const [filteredSellers, setFilteredSellers] = useState<Seller[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('All');
  const [selectedSeller, setSelectedSeller] = useState<Seller | null>(null);
  const [showDetailsModal, setShowDetailsModal] = useState(false);
  const [showCommissionModal, setShowCommissionModal] = useState(false);
  const [newCommission, setNewCommission] = useState(0);

  useEffect(() => {
    fetchSellers();
  }, []);

  useEffect(() => {
    filterSellers();
  }, [sellers, searchTerm, statusFilter]);

  const fetchSellers = async () => {
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from('sellers')
        .select(`
          id,
          store_name,
          owner_id,
          category,
          status,
          products_count,
          total_earnings,
          is_verified,
          commission_rate,
          profiles!owner_id(email)
        `)
        .order('created_at', { ascending: false });

      if (error) throw error;

      const formattedData = (data || []).map((seller: any) => ({
        ...seller,
        owner_email: seller.profiles?.email || 'N/A',
      }));

      setSellers(formattedData);
    } catch (error) {
      console.error('Error fetching sellers:', error);
    } finally {
      setLoading(false);
    }
  };

  const filterSellers = () => {
    let filtered = [...sellers];

    if (searchTerm) {
      filtered = filtered.filter(
        (seller) =>
          seller.store_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
          seller.owner_email.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    if (statusFilter !== 'All') {
      filtered = filtered.filter((seller) => seller.status === statusFilter.toLowerCase());
    }

    setFilteredSellers(filtered);
  };

  const handleStatusChange = async (sellerId: string, newStatus: string) => {
    try {
      const { error } = await supabase
        .from('sellers')
        .update({ status: newStatus })
        .eq('id', sellerId);

      if (error) throw error;

      setSellers(sellers.map((s) => (s.id === sellerId ? { ...s, status: newStatus as any } : s)));
    } catch (error) {
      console.error('Error updating seller status:', error);
    }
  };

  const handleToggleVerification = async (sellerId: string, currentVerification: boolean) => {
    try {
      const { error } = await supabase
        .from('sellers')
        .update({ is_verified: !currentVerification })
        .eq('id', sellerId);

      if (error) throw error;

      setSellers(sellers.map((s) => (s.id === sellerId ? { ...s, is_verified: !currentVerification } : s)));
    } catch (error) {
      console.error('Error updating verification status:', error);
    }
  };

  const handleUpdateCommission = async (sellerId: string) => {
    try {
      const { error } = await supabase
        .from('sellers')
        .update({ commission_rate: newCommission })
        .eq('id', sellerId);

      if (error) throw error;

      setSellers(sellers.map((s) => (s.id === sellerId ? { ...s, commission_rate: newCommission } : s)));
      setShowCommissionModal(false);
      setSelectedSeller(null);
    } catch (error) {
      console.error('Error updating commission rate:', error);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'active':
        return 'bg-green-100 text-green-800';
      case 'pending':
        return 'bg-yellow-100 text-yellow-800';
      case 'suspended':
        return 'bg-red-100 text-red-800';
      case 'rejected':
        return 'bg-gray-100 text-gray-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-gray-600">Loading sellers...</div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-3xl font-bold text-gray-900">Seller Management</h1>
        <p className="text-gray-600 mt-2">Manage vendors and their store details</p>
      </div>

      {/* Filters */}
      <Card>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Search</label>
            <Input
              placeholder="Search by store name or email..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              icon={<Search className="w-4 h-4" />}
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Status</label>
            <Select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)}>
              <option>All</option>
              <option>Active</option>
              <option>Pending</option>
              <option>Suspended</option>
              <option>Rejected</option>
            </Select>
          </div>
          <div className="flex items-end">
            <Button
              variant="secondary"
              className="w-full"
              onClick={() => {
                setSearchTerm('');
                setStatusFilter('All');
              }}
            >
              Reset Filters
            </Button>
          </div>
        </div>
      </Card>

      {/* Sellers Table */}
      <Card>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b">
                <th className="px-6 py-3 text-left text-sm font-semibold text-gray-700">Store Name</th>
                <th className="px-6 py-3 text-left text-sm font-semibold text-gray-700">Owner</th>
                <th className="px-6 py-3 text-left text-sm font-semibold text-gray-700">Category</th>
                <th className="px-6 py-3 text-left text-sm font-semibold text-gray-700">Status</th>
                <th className="px-6 py-3 text-center text-sm font-semibold text-gray-700">Products</th>
                <th className="px-6 py-3 text-right text-sm font-semibold text-gray-700">Revenue</th>
                <th className="px-6 py-3 text-center text-sm font-semibold text-gray-700">Verified</th>
                <th className="px-6 py-3 text-right text-sm font-semibold text-gray-700">Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredSellers.map((seller) => (
                <tr key={seller.id} className="border-b hover:bg-gray-50 transition-colors">
                  <td className="px-6 py-4">
                    <p className="font-medium text-gray-900">{seller.store_name}</p>
                  </td>
                  <td className="px-6 py-4">
                    <p className="text-sm text-gray-600">{seller.owner_email}</p>
                  </td>
                  <td className="px-6 py-4">
                    <span className="text-sm text-gray-600">{seller.category}</span>
                  </td>
                  <td className="px-6 py-4">
                    <Badge className={getStatusColor(seller.status)}>
                      {seller.status.charAt(0).toUpperCase() + seller.status.slice(1)}
                    </Badge>
                  </td>
                  <td className="px-6 py-4 text-center">
                    <span className="text-sm font-medium text-gray-900">{seller.products_count}</span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <span className="font-semibold text-orange-600">${seller.total_earnings.toLocaleString()}</span>
                  </td>
                  <td className="px-6 py-4 text-center">
                    {seller.is_verified ? (
                      <CheckCircle className="w-5 h-5 text-green-600 mx-auto" />
                    ) : (
                      <XCircle className="w-5 h-5 text-gray-400 mx-auto" />
                    )}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2">
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => {
                          setSelectedSeller(seller);
                          setShowDetailsModal(true);
                        }}
                        icon={<Eye className="w-4 h-4" />}
                      />
                      {seller.status === 'pending' && (
                        <>
                          <Button
                            variant="success"
                            size="sm"
                            onClick={() => handleStatusChange(seller.id, 'active')}
                            icon={<CheckCircle className="w-4 h-4" />}
                          />
                          <Button
                            variant="error"
                            size="sm"
                            onClick={() => handleStatusChange(seller.id, 'rejected')}
                            icon={<XCircle className="w-4 h-4" />}
                          />
                        </>
                      )}
                      {seller.status === 'active' && (
                        <Button
                          variant="warning"
                          size="sm"
                          onClick={() => handleStatusChange(seller.id, 'suspended')}
                          icon={<AlertCircle className="w-4 h-4" />}
                        />
                      )}
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => handleToggleVerification(seller.id, seller.is_verified)}
                        icon={<ToggleLeft className="w-4 h-4" />}
                      />
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {filteredSellers.length === 0 && (
          <div className="text-center py-12">
            <p className="text-gray-600">No sellers found matching your criteria.</p>
          </div>
        )}

        <div className="mt-4 text-sm text-gray-600 border-t pt-4">
          Showing {filteredSellers.length} of {sellers.length} sellers
        </div>
      </Card>

      {/* Seller Details Modal */}
      <Modal
        isOpen={showDetailsModal}
        onClose={() => setShowDetailsModal(false)}
        title="Seller Details"
      >
        {selectedSeller && (
          <div className="space-y-4">
            <div className="border-b pb-4">
              <h3 className="text-lg font-semibold text-gray-900">{selectedSeller.store_name}</h3>
              <p className="text-gray-600 mt-1">{selectedSeller.owner_email}</p>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-sm font-medium text-gray-700">Category</label>
                <p className="text-gray-900 mt-1">{selectedSeller.category}</p>
              </div>
              <div>
                <label className="text-sm font-medium text-gray-700">Status</label>
                <p className="text-gray-900 mt-1 capitalize">{selectedSeller.status}</p>
              </div>
              <div>
                <label className="text-sm font-medium text-gray-700">Products</label>
                <p className="text-gray-900 mt-1">{selectedSeller.products_count}</p>
              </div>
              <div>
                <label className="text-sm font-medium text-gray-700">Total Revenue</label>
                <p className="text-orange-600 mt-1 font-semibold">${selectedSeller.total_earnings.toLocaleString()}</p>
              </div>
              <div>
                <label className="text-sm font-medium text-gray-700">Commission Rate</label>
                <p className="text-gray-900 mt-1">{selectedSeller.commission_rate}%</p>
              </div>
              <div>
                <label className="text-sm font-medium text-gray-700">Verified</label>
                <p className="text-gray-900 mt-1">{selectedSeller.is_verified ? 'Yes' : 'No'}</p>
              </div>
            </div>

            <div className="flex gap-3 mt-6 border-t pt-4">
              <Button
                variant="secondary"
                onClick={() => {
                  setNewCommission(selectedSeller.commission_rate);
                  setShowCommissionModal(true);
                }}
              >
                Edit Commission
              </Button>
              <Button variant="secondary" onClick={() => setShowDetailsModal(false)}>
                Close
              </Button>
            </div>
          </div>
        )}
      </Modal>

      {/* Commission Modal */}
      <Modal
        isOpen={showCommissionModal}
        onClose={() => setShowCommissionModal(false)}
        title="Edit Commission Rate"
      >
        {selectedSeller && (
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Commission Rate (%)</label>
              <Input
                type="number"
                min="0"
                max="100"
                value={newCommission}
                onChange={(e) => setNewCommission(parseFloat(e.target.value))}
              />
            </div>

            <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 text-sm text-blue-800">
              Updating commission for <strong>{selectedSeller.store_name}</strong>
            </div>

            <div className="flex gap-3 mt-6 border-t pt-4">
              <Button variant="secondary" onClick={() => setShowCommissionModal(false)}>
                Cancel
              </Button>
              <Button onClick={() => handleUpdateCommission(selectedSeller.id)}>
                Update Commission
              </Button>
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
};

export default Sellers;
